#!/usr/bin/env bash
# usability-testing.sh — 可用性测试（usability testing） SOP walkthrough for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
WORKFLOW="可用性测试（usability testing）"

usage() {
  cat <<EOF
usability-testing.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./usability-testing.sh             # interactive
  ./usability-testing.sh --dry-run
  ./usability-testing.sh --json
  ./usability-testing.sh --explain
  ./usability-testing.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "可用性测试（usability testing）" 工作流。

一句话: 从「我们以为这个设计好用」到「看真人真实使用，发现他们实际卡在哪」，把意见之争变成观察证据。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定目标 + 写任务**: 明确测什么流程，写真实场景的任务（\"给朋友买张生日礼券\"而非\"用搜索功能\"）。跳过→测了无关紧要的东西，或任务诱导了答案。 (evidence: [T03-S003, T03-S004])"
  "**选方法**: 有主持（moderated，能追问，适合早期探索）vs 无主持（unmoderated，快、量大，适合验证）。跳过→方法错配研究目标，浪费。 (evidence: [T03-S003, T03-S004])"
  "**招募 ~5 名/段目标用户**: Nielsen「5 用户能发现约 85% 问题」经验法则。跳过→样本太少漏问题，或太多边际收益递减浪费钱。 (evidence: [T03-S005])"
  "**pilot（试跑 1 人）**: 先跑一个，校验任务清晰度和工具。跳过→正式测试才发现任务有歧义，全部数据作废。 (evidence: [T03-S004])"
  "**执行 + 观察**: 让用户出声思考（think-aloud），主持人少干预，记录卡点。跳过→只看结果不看过程，不知道\"为什么\"卡。 (evidence: [T03-S003])"
  "**分析 + 报告**: 按严重度归纳问题，给可行动修复建议。跳过→发现问题但不修，测试白做。 (evidence: [T03-S004])"
)
declare -a FAILURE_MODES=(
  "主持人引导用户: \"你想点哪个？是不是这里？\"污染数据。坐后面闭嘴，让用户自己撞墙。 (evidence: [T03-S003])"
  "把测试当作品 demo: 向用户推销设计而非观察其使用。 (evidence: [T03-S003])"
  "拿喜好当可用性: 问\"好看吗\"而非看\"能不能完成任务\"。可用性测能力，不是测审美偏好。 (evidence: [T03-S003])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "usability-testing-walkthrough"
fi
